WITH s AS (SELECT brand_name, SUM(shipped_units) AS shipped_units FROM shipped_raw WHERE brand_name IS NOT NULL GROUP BY brand_name), c AS (SELECT brand_name, SUM(conceded_units) AS conceded_units FROM concession_raw WHERE brand_name IS NOT NULL GROUP BY brand_name) SELECT s.brand_name, s.shipped_units, COALESCE(c.conceded_units, 0) AS conceded_units, (COALESCE(c.conceded_units, 0) * 100.0) / NULLIF(s.shipped_units, 0) AS return_rate_pct FROM s JOIN c ON c.brand_name = s.brand_name WHERE COALESCE(c.conceded_units, 0) > 0 ORDER BY return_rate_pct DESC;